export interface HotSearchItem {
  id: string;
  title: string;
  summary?: string;
  source: string;
  sourceName: string;
  sourceColor: string;
  hotScore: number;
  imageUrl?: string;
  originalUrl: string;
  tags: string[];
  publishTime: Date;
}

export interface ApiConfig {
  baseUrl: string;
  apiKey?: string;
  timeout?: number;
}

const defaultConfig: ApiConfig = {
  baseUrl: 'https://api.example.com',
  timeout: 10000,
};

export class HotSearchApi {
  private config: ApiConfig;

  constructor(config: Partial<ApiConfig> = {}) {
    this.config = { ...defaultConfig, ...config };
  }

  private async fetchWithTimeout(url: string, options: RequestInit = {}, timeout = 10000): Promise<Response> {
    const controller = new AbortController();
    const timeoutId = setTimeout(() => controller.abort(), timeout);

    try {
      const response = await fetch(url, {
        ...options,
        signal: controller.signal,
      });
      clearTimeout(timeoutId);
      return response;
    } catch (error) {
      clearTimeout(timeoutId);
      throw error;
    }
  }

  async fetchWeiboHotSearch(): Promise<HotSearchItem[]> {
    try {
      console.log('正在获取微博热搜...');
      const response = await this.fetchWithTimeout(
        'https://m.weibo.cn/api/container/getIndex?type=wb&containerid=106003type=25&t=3',
        {
          headers: {
            'User-Agent': 'Mozilla/5.0 (iPhone; CPU iPhone OS 14_0 like Mac OS X) AppleWebKit/605.1.15 (KHTML, like Gecko) Version/14.0 Mobile/15E148 Safari/604.1',
            'Referer': 'https://m.weibo.cn/',
            'Accept': 'application/json, text/plain, */*',
          },
        }
      );

      if (!response.ok) {
        console.error(`微博API错误: ${response.status} ${response.statusText}`);
        return [];
      }

      const data = await response.json();
      console.log('微博热搜数据:', data);
      return this.parseWeiboData(data);
    } catch (error) {
      console.error('获取微博热搜失败:', error);
      return [];
    }
  }

  async fetchZhihuHotSearch(): Promise<HotSearchItem[]> {
    try {
      console.log('正在获取知乎热榜...');
      const response = await this.fetchWithTimeout(
        'https://www.zhihu.com/api/v3/feed/topstory/hot-list',
        {
          headers: {
            'User-Agent': 'Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36',
            'Referer': 'https://www.zhihu.com/hot',
            'Accept': 'application/json, text/plain, */*',
          },
        }
      );

      if (!response.ok) {
        console.error(`知乎API错误: ${response.status} ${response.statusText}`);
        return [];
      }

      const data = await response.json();
      console.log('知乎热榜数据:', data);
      return this.parseZhihuData(data);
    } catch (error) {
      console.error('获取知乎热榜失败:', error);
      return [];
    }
  }

  async fetchBilibiliHotSearch(): Promise<HotSearchItem[]> {
    try {
      console.log('正在获取B站热门...');
      const response = await this.fetchWithTimeout(
        'https://api.bilibili.com/x/web-interface/popular',
        {
          headers: {
            'User-Agent': 'Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36',
            'Referer': 'https://www.bilibili.com/',
            'Accept': 'application/json, text/plain, */*',
          },
        }
      );

      if (!response.ok) {
        console.error(`B站API错误: ${response.status} ${response.statusText}`);
        return [];
      }

      const data = await response.json();
      console.log('B站热门数据:', data);
      return this.parseBilibiliData(data);
    } catch (error) {
      console.error('获取B站热门失败:', error);
      return [];
    }
  }

  async fetchGitHubTrending(): Promise<HotSearchItem[]> {
    try {
      console.log('正在获取GitHub趋势...');
      const response = await this.fetchWithTimeout(
        'https://api.github.com/search/repositories?q=stars:>1000+created:>2024-01-01&sort=stars&order=desc&per_page=20',
        {
          headers: {
            'User-Agent': 'Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36',
            'Accept': 'application/vnd.github.v3+json',
          },
        }
      );

      if (!response.ok) {
        console.error(`GitHub API错误: ${response.status} ${response.statusText}`);
        return [];
      }

      const data = await response.json();
      console.log('GitHub趋势数据:', data);
      return this.parseGitHubData(data);
    } catch (error) {
      console.error('获取GitHub趋势失败:', error);
      return [];
    }
  }

  private parseWeiboData(data: any): HotSearchItem[] {
    const items: HotSearchItem[] = [];
    
    if (!data || !data.ok) {
      console.warn('微博返回数据无效:', data);
      return items;
    }

    const cards = data?.data?.cards || [];
    
    cards.forEach((card: any) => {
      const cardGroup = card?.card_group || [card];
      cardGroup.forEach((item: any) => {
        if (item?.title || item?.raw_text) {
          items.push({
            id: `weibo-${item.itemid || Math.random().toString(36)}`,
            title: item.title || item.raw_text || '',
            summary: item.desc || '',
            source: 'weibo',
            sourceName: '微博',
            sourceColor: '#E6162D',
            hotScore: parseInt(item.hot || item.realpos || item.mblog?.attitudes_count || '0'),
            imageUrl: item.pic?.url || item.mblog?.bmiddle_pic,
            originalUrl: item.scheme || `https://m.weibo.cn/detail/${item.itemid}`,
            tags: ['social', '热门', '实时'],
            publishTime: new Date(),
          });
        }
      });
    });

    console.log(`解析到 ${items.length} 条微博热搜`);
    return items;
  }

  private parseZhihuData(data: any): HotSearchItem[] {
    const items: HotSearchItem[] = [];
    
    if (!data || !data.data) {
      console.warn('知乎返回数据无效:', data);
      return items;
    }

    const hotList = data.data || [];
    
    hotList.forEach((item: any, index: number) => {
      const target = item?.target || item;
      items.push({
        id: `zhihu-${target.id || index}`,
        title: target.title || target.question?.title || '',
        summary: target.excerpt || target.question?.excerpt || '',
        source: 'zhihu',
        sourceName: '知乎',
        sourceColor: '#0084FF',
        hotScore: parseInt(item.score || target.voteup_count || '0'),
        imageUrl: target.thumbnail?.url || target.feed_highlight?.url,
        originalUrl: target.url?.replace('/api/v4', '') || `https://www.zhihu.com/question/${target.id}`,
        tags: ['social', '热门', '实时'],
        publishTime: new Date(),
      });
    });

    console.log(`解析到 ${items.length} 条知乎热榜`);
    return items;
  }

  private parseBilibiliData(data: any): HotSearchItem[] {
    const items: HotSearchItem[] = [];
    
    if (!data || !data.data) {
      console.warn('B站返回数据无效:', data);
      return items;
    }

    const list = data.data?.list || [];
    
    list.forEach((item: any) => {
      if (item?.title) {
        items.push({
          id: `bilibili-${item.aid || Math.random().toString(36)}`,
          title: item.title || '',
          summary: item.desc || '',
          source: 'bilibili',
          sourceName: '哔哩哔哩',
          sourceColor: '#00A1D6',
          hotScore: parseInt(item.stat?.view || item.view || '0'),
          imageUrl: item.pic || item.cover,
          originalUrl: item.uri?.replace('bilibili://', 'https://www.bilibili.com/video/') || `https://www.bilibili.com/video/av${item.aid}`,
          tags: ['video', '热门', '实时'],
          publishTime: new Date(),
        });
      }
    });

    console.log(`解析到 ${items.length} 条B站热门`);
    return items;
  }

  private parseGitHubData(data: any): HotSearchItem[] {
    const items: HotSearchItem[] = [];
    
    if (!data || !data.items) {
      console.warn('GitHub返回数据无效:', data);
      return items;
    }

    const repos = data.items || [];
    
    repos.forEach((item: any) => {
      items.push({
        id: `github-${item.id || item.name}`,
        title: `${item.full_name || item.name}: ${item.description || ''}`,
        summary: item.description || '',
        source: 'github',
        sourceName: 'GitHub',
        sourceColor: '#24292F',
        hotScore: parseInt(item.stargazers_count || '0'),
        imageUrl: item.owner?.avatar_url,
        originalUrl: item.html_url || item.url,
        tags: ['tech', '热门', '趋势'],
        publishTime: new Date(item.created_at || Date.now()),
      });
    });

    console.log(`解析到 ${items.length} 条GitHub趋势`);
    return items;
  }

  async fetchAllHotSearches(): Promise<HotSearchItem[]> {
    console.log('开始获取所有平台热搜...');
    
    const promises = [
      this.fetchWeiboHotSearch(),
      this.fetchZhihuHotSearch(),
      this.fetchBilibiliHotSearch(),
      this.fetchGitHubTrending(),
    ];

    const results = await Promise.allSettled(promises);
    const allItems: HotSearchItem[] = [];

    results.forEach((result, index) => {
      const platforms = ['微博', '知乎', 'B站', 'GitHub'];
      if (result.status === 'fulfilled') {
        console.log(`${platforms[index]}: 获取成功`);
        allItems.push(...result.value);
      } else {
        console.error(`${platforms[index]}: 获取失败 -`, result.reason);
      }
    });

    console.log(`总计获取 ${allItems.length} 条热点`);
    
    if (allItems.length === 0) {
      console.warn('所有平台API都获取失败，可能是跨域限制或网络问题');
    }

    return allItems.sort((a, b) => b.hotScore - a.hotScore);
  }
}

export const hotSearchApi = new HotSearchApi();
