import { NewsItem } from '@/types';
import { NewsCard } from './NewsCard';

interface NewsGridProps {
  news: NewsItem[];
  loading?: boolean;
}

const SkeletonCard = () => (
  <div className="news-card animate-pulse">
    <div className="h-40 bg-surface-active rounded-t-xl -mx-4 -mt-4 mb-3" />
    <div className="space-y-3">
      <div className="h-5 bg-surface-active rounded w-3/4" />
      <div className="h-4 bg-surface-active rounded w-full" />
      <div className="h-4 bg-surface-active rounded w-2/3" />
      <div className="flex items-center gap-3 pt-2">
        <div className="h-4 bg-surface-active rounded w-16" />
        <div className="h-4 bg-surface-active rounded w-12" />
      </div>
    </div>
  </div>
);

export const NewsGrid = ({ news, loading }: NewsGridProps) => {
  if (loading) {
    return (
      <div className="grid grid-cols-1 md:grid-cols-2 xl:grid-cols-3 gap-4">
        {Array.from({ length: 9 }).map((_, i) => (
          <SkeletonCard key={i} />
        ))}
      </div>
    );
  }

  if (news.length === 0) {
    return (
      <div className="flex flex-col items-center justify-center py-20">
        <div className="w-24 h-24 rounded-full bg-surface flex items-center justify-center mb-4">
          <span className="text-4xl">🔍</span>
        </div>
        <h3 className="text-lg font-semibold text-text-primary mb-2">暂无相关热点</h3>
        <p className="text-text-muted">试试切换其他平台或搜索关键词</p>
      </div>
    );
  }

  return (
    <div className="grid grid-cols-1 md:grid-cols-2 xl:grid-cols-3 gap-4">
      {news.map((item, index) => (
        <NewsCard key={item.id} news={item} index={index} />
      ))}
    </div>
  );
};
