import React, { useEffect, useState } from 'react';
import { motion } from 'framer-motion';
import { Layout } from '@/components/layout';
import { PlatformTabs, NewsGrid } from '@/components/news';
import { useNewsStore } from '@/stores/newsStore';
import { useAihotStore } from '@/stores/aihotStore';

type DataSource = 'mock' | 'realtime' | 'aihot';

export const Home = () => {
  const { getFilteredNews, loading, selectedPlatform, searchQuery, sortBy } = useNewsStore();
  const { items: aihotItems, loading: aihotLoading, fetchItems } = useAihotStore();
  const [dataSource, setDataSource] = useState<DataSource>('mock');

  useEffect(() => {
    const handleStorageChange = () => {
      const savedSource = localStorage.getItem('dataSource') as DataSource;
      if (savedSource) {
        setDataSource(savedSource);
      }
    };

    handleStorageChange();
    window.addEventListener('storage', handleStorageChange);
    
    const interval = setInterval(handleStorageChange, 1000);

    return () => {
      window.removeEventListener('storage', handleStorageChange);
      clearInterval(interval);
    };
  }, []);

  useEffect(() => {
    if (dataSource === 'aihot') {
      fetchItems();
    }
  }, [dataSource, fetchItems]);

  useEffect(() => {
    localStorage.setItem('dataSource', dataSource);
  }, [dataSource]);

  const filteredNews = dataSource === 'aihot' ? aihotItems : getFilteredNews();
  const isLoading = dataSource === 'aihot' ? aihotLoading : loading;

  const getTitle = () => {
    if (dataSource === 'aihot') {
      return '🤖 AIHOT 精选';
    }
    if (dataSource === 'realtime') {
      return '🔴 实时热点';
    }
    return selectedPlatform === 'all' ? '全网热点' : `${selectedPlatform}热点`;
  };

  const getDescription = () => {
    if (dataSource === 'aihot') {
      return 'AIHOT 每日从几百个信源中精选的高价值 AI 资讯';
    }
    if (dataSource === 'realtime') {
      return `共 ${filteredNews.length} 条实时热点 · ${searchQuery && `搜索 "${searchQuery}"`} ${sortBy === 'hot' ? '· 按热度排序' : '· 按时间排序'}`;
    }
    return `共 ${filteredNews.length} 条热点 ${searchQuery && `· 搜索 "${searchQuery}"`} ${sortBy === 'hot' ? '· 按热度排序' : '· 按时间排序'}`;
  };

  return (
    <Layout>
      <motion.div
        initial={{ opacity: 0 }}
        animate={{ opacity: 1 }}
        transition={{ duration: 0.5 }}
      >
        <div className="mb-8">
          <motion.div
            initial={{ opacity: 0, y: -20 }}
            animate={{ opacity: 1, y: 0 }}
            transition={{ delay: 0.2 }}
          >
            <h2 className="text-2xl font-bold font-display text-text-primary mb-2">
              {getTitle()}
            </h2>
            <p className="text-text-muted">
              {getDescription()}
            </p>
          </motion.div>
        </div>

        {dataSource !== 'aihot' && <PlatformTabs />}

        <NewsGrid news={filteredNews} loading={isLoading} />
      </motion.div>
    </Layout>
  );
};
