import { Link } from 'react-router-dom';
import { motion } from 'framer-motion';
import { Heart, ExternalLink, Clock, Flame } from 'lucide-react';
import { NewsItem } from '@/types';
import { useFavoritesStore } from '@/stores/favoritesStore';
import { formatTime, formatNumber, getHotLevel } from '@/utils/formatters';

interface NewsCardProps {
  news: NewsItem;
  index: number;
}

export const NewsCard = ({ news, index }: NewsCardProps) => {
  const { isFavorite, toggleFavorite } = useFavoritesStore();
  const hotLevel = getHotLevel(news.hotScore);
  const isFav = isFavorite(news.id);

  const handleFavoriteClick = (e: React.MouseEvent) => {
    e.preventDefault();
    e.stopPropagation();
    toggleFavorite(news.id);
  };

  const handleExternalClick = (e: React.MouseEvent) => {
    e.stopPropagation();
  };

  return (
    <motion.div
      initial={{ opacity: 0, y: 20 }}
      animate={{ opacity: 1, y: 0 }}
      transition={{ duration: 0.4, delay: index * 0.05 }}
      className="group"
    >
      <Link to={`/detail/${news.id}`}>
        <div 
          className="news-card relative overflow-hidden cursor-pointer"
          style={{ borderLeftColor: news.sourceColor, borderLeftWidth: '3px' }}
        >
          {news.imageUrl && (
            <div className="relative h-40 -mx-4 -mt-4 mb-3 overflow-hidden rounded-t-xl">
              <img
                src={news.imageUrl}
                alt={news.title}
                className="w-full h-full object-cover transition-transform duration-500 group-hover:scale-105"
                loading="lazy"
              />
              <div className="absolute inset-0 bg-gradient-to-t from-surface/80 to-transparent" />
            </div>
          )}

          <div className="space-y-2">
            <div className="flex items-start justify-between gap-2">
              <h3 className="text-base font-semibold text-text-primary line-clamp-2 group-hover:text-accent-amber transition-colors">
                {news.title}
              </h3>
              {hotLevel.label && (
                <span className={`shrink-0 px-2 py-0.5 rounded text-xs font-bold ${hotLevel.color} bg-current/10`}>
                  {hotLevel.label}
                </span>
              )}
            </div>

            <p className="text-sm text-text-secondary line-clamp-2">
              {news.summary}
            </p>

            <div className="flex items-center justify-between pt-2 border-t border-border/30">
              <div className="flex items-center gap-3">
                <span 
                  className="text-xs font-medium px-2 py-0.5 rounded-full"
                  style={{ backgroundColor: `${news.sourceColor}20`, color: news.sourceColor }}
                >
                  {news.sourceName}
                </span>
                <span className="flex items-center gap-1 text-xs text-text-muted">
                  <Clock className="w-3 h-3" />
                  {formatTime(news.publishTime)}
                </span>
              </div>

              <div className="flex items-center gap-2">
                <span className="flex items-center gap-1 text-xs text-text-muted">
                  <Flame className="w-3 h-3 text-accent-orange" />
                  {formatNumber(news.hotScore)}
                </span>
              </div>
            </div>

            <div className="flex items-center gap-2 pt-1">
              {news.tags.slice(0, 3).map((tag, i) => (
                <span key={i} className="text-xs text-text-muted bg-surface-active px-2 py-0.5 rounded">
                  {tag}
                </span>
              ))}
            </div>
          </div>

          <div className="absolute top-3 right-3 flex items-center gap-1 opacity-0 group-hover:opacity-100 transition-opacity">
            <motion.button
              whileHover={{ scale: 1.1 }}
              whileTap={{ scale: 0.9 }}
              onClick={handleFavoriteClick}
              className={`p-2 rounded-full backdrop-blur-sm transition-colors ${
                isFav 
                  ? 'bg-red-500/20 text-red-400' 
                  : 'bg-surface/80 text-text-muted hover:text-red-400'
              }`}
            >
              <Heart className={`w-4 h-4 ${isFav ? 'fill-current' : ''}`} />
            </motion.button>
          </div>
        </div>
      </Link>
    </motion.div>
  );
};
